#!/bin/bash
set -euo pipefail
INPUT=$(head -c 65536)
FILE=$(printf '%s' "$INPUT" | jq -r '.tool_input.file_path // .tool_input.path // ""')
if [ -z "$FILE" ] || [ ! -f "$FILE" ]; then echo '{"decision":"approve"}'; exit 0; fi
REAL=$(realpath "$FILE" 2>/dev/null) || { echo '{"decision":"approve"}'; exit 0; }
WD=$(realpath "$PWD")
[[ "$REAL" != "$WD"/* ]] && { echo '{"decision":"approve"}'; exit 0; }
BN=$(basename "$REAL")
[[ "$BN" == -* ]] && { echo '{"decision":"approve"}'; exit 0; }
case "$REAL" in
  *.ts|*.tsx|*.js|*.jsx|*.json|*.css|*.scss|*.md) npx -y prettier --write "$REAL" 2>/dev/null || true ;;
  *.py) black "$REAL" 2>/dev/null || ruff format "$REAL" 2>/dev/null || true ;;
  *.rs) rustfmt "$REAL" 2>/dev/null || true ;;
  *.go) gofmt -w "$REAL" 2>/dev/null || true ;;
esac
echo '{"decision":"approve"}'
